// ── Shared Components ────────────────────────────────────────

const BucketIcon = ({ bucket, size = 40, style }: any) => {
  const cfg = B[bucket];
  return (
    <View style={[{
      width: size, height: size, borderRadius: size * 0.28,
      backgroundColor: cfg.light, alignItems: 'center', justifyContent: 'center',
      borderWidth: 1.5, borderColor: cfg.mid,
    }, style]}>
      <Text style={{ fontSize: size * 0.38, color: cfg.color, fontWeight: '900' }}>{cfg.shape}</Text>
    </View>
  );
};

const Avatar = ({ size = 66 }: any) => (
  <View style={{
    width: size, height: size, borderRadius: size * 0.28,
    backgroundColor: C.dark2, alignItems: 'center', justifyContent: 'center',
    borderWidth: 1.5, borderColor: C.darkB, overflow: 'hidden',
  }}>
    <Image
      source={{ uri: size >= 80 ? BIRD_128 : BIRD_96 }}
      style={{ width: size * 0.92, height: size * 0.92 }}
      resizeMode="contain"
    />
  </View>
);

// Shared screen header — fixed, not scrollable
const ScreenHeader = ({ title, subtitle, right, onBack }: any) => {
  const insets = useSafeAreaInsets();
  return (
    <View style={{
      backgroundColor: C.card,
      paddingTop: insets.top + 8,
      paddingBottom: 12,
      paddingHorizontal: 16,
      flexDirection: 'row',
      alignItems: 'center',
      borderBottomWidth: 1,
      borderBottomColor: C.cardB,
    }}>
      {onBack
        ? <TouchableOpacity onPress={onBack} style={{ width: 80 }}>
            <Text style={{ fontSize: 15, color: C.brand, fontWeight: '600' }}>← Back</Text>
          </TouchableOpacity>
        : <View style={{ width: 80 }} />}
      <View style={{ flex: 1, alignItems: 'center' }}>
        <Text style={{ fontSize: 17, fontWeight: '800', color: C.t1 }}>{title}</Text>
        {subtitle ? <Text style={{ fontSize: 11, color: C.t4, marginTop: 1 }}>{subtitle}</Text> : null}
      </View>
      <View style={{ width: 80, alignItems: 'flex-end' }}>{right || null}</View>
    </View>
  );
};

// ═══════════════════════════════════════════════════════════
// HOME SCREEN
// ═══════════════════════════════════════════════════════════
const HomeScreen = ({ nav, summary, transactions, limits }: any) => {
  const insets = useSafeAreaInsets();
  const pending = transactions.filter((t: any) => !t.bucket).length;
  const hour = new Date().getHours();
  const greeting = hour < 12 ? 'Good Morning' : hour < 17 ? 'Good Afternoon' : 'Good Evening';
  const quote = QUOTES[new Date().getDay() % QUOTES.length];
  const fade = useRef(new Animated.Value(0)).current;
  useEffect(() => {
    Animated.timing(fade, { toValue: 1, duration: 500, useNativeDriver: true }).start();
  }, []);

  return (
    <View style={{ flex: 1, backgroundColor: C.dark }}>
      <StatusBar barStyle="light-content" backgroundColor={C.dark} />
      <ScrollView
        style={{ flex: 1 }}
        contentContainerStyle={{ paddingBottom: 20 }}
        showsVerticalScrollIndicator={false}
        bounces
      >
        <Animated.View style={{ opacity: fade }}>

          {/* Hero — respects top inset for Dynamic Island / notch */}
          <View style={[H.hero, { paddingTop: insets.top + 10 }]}>
            <View style={H.topRow}>
              <View>
                <Text style={H.greetTiny}>{greeting}</Text>
                <Text style={H.greetName}>Sandeep</Text>
              </View>
              <TouchableOpacity style={H.infoBtn} onPress={() => nav('Education')}>
                <Text style={H.infoBtnText}>?</Text>
              </TouchableOpacity>
            </View>

            <View style={H.wallet}>
              <View>
                <Avatar size={64} />
              </View>
              <View style={{ flex: 1 }}>
                <View style={H.quoteDash} />
                <Text style={H.quoteText}>{quote}</Text>
              </View>
            </View>

            {summary.total > 0 && (
              <View style={H.totalStrip}>
                <Text style={H.totalLabel}>Month Total</Text>
                <Text style={H.totalAmt}>Rs. {summary.total.toLocaleString('en-IN')}</Text>
              </View>
            )}
          </View>

          {/* Light content */}
          <View style={H.content}>
            {pending > 0 && (
              <TouchableOpacity style={H.banner} onPress={() => nav('Sort')}>
                <View style={H.bannerDot} />
                <View style={{ flex: 1 }}>
                  <Text style={H.bannerTitle}>{pending} spend{pending > 1 ? 's' : ''} waiting to be sorted</Text>
                  <Text style={H.bannerSub}>tap to classify from bank messages</Text>
                </View>
                <Text style={H.bannerArrow}>Sort ›</Text>
              </TouchableOpacity>
            )}

            <View style={{ flexDirection: 'row', justifyContent: 'space-between', alignItems: 'center', marginBottom: 14 }}>
              <Text style={H.sectionLabel}>THIS MONTH</Text>
              <TouchableOpacity onPress={() => nav('Limits')}>
                <Text style={{ fontSize: 11, color: C.brand, fontWeight: '700' }}>Set Limits ›</Text>
              </TouchableOpacity>
            </View>

            <View style={H.grid}>
              {Object.entries(B).map(([key, cfg]: any) => {
                const amt = summary[key] || 0;
                const limit = limits[key] || 0;
                const isOver = limit > 0 && amt > limit;
                const isNear = limit > 0 && amt >= limit * 0.8 && !isOver;
                const pct = limit > 0 ? Math.min((amt / limit) * 100, 100) : 0;
                return (
                  <TouchableOpacity key={key}
                    style={[H.bucketCard, isOver && { borderColor: C.danger }]}
                    onPress={() => nav('Pie')}>
                    <View style={[H.bucketAccent, { backgroundColor: isOver ? C.danger : cfg.color }]} />
                    <BucketIcon bucket={key} size={32} style={{ marginBottom: 6 }} />
                    <Text style={[H.bucketAmt, { color: isOver ? C.danger : cfg.color }]}>
                      {amt >= 1000 ? `Rs.${(amt / 1000).toFixed(1)}k` : `Rs.${amt}`}
                    </Text>
                    <Text style={H.bucketName}>{cfg.label}</Text>
                    {isOver && <Text style={{ fontSize: 8, color: C.danger, fontWeight: '800', marginTop: 2 }}>OVER LIMIT</Text>}
                    {isNear && <Text style={{ fontSize: 8, color: C.warning, fontWeight: '800', marginTop: 2 }}>NEAR LIMIT</Text>}
                    {limit > 0 && (
                      <View style={{ marginTop: 6, width: '100%', height: 4, backgroundColor: cfg.light, borderRadius: 2, overflow: 'hidden' }}>
                        <View style={{ height: 4, width: `${pct}%`, backgroundColor: isOver ? C.danger : isNear ? C.warning : cfg.color, borderRadius: 2 }} />
                      </View>
                    )}
                  </TouchableOpacity>
                );
              })}
            </View>

            <TouchableOpacity style={H.primaryBtn} onPress={() => nav('Sort')}>
              <Text style={H.primaryBtnText}>Scan Bank Messages</Text>
            </TouchableOpacity>
            <TouchableOpacity style={H.secondaryBtn} onPress={() => nav('ManualAdd')}>
              <Text style={H.secondaryBtnText}>+  Add Manually</Text>
            </TouchableOpacity>

            <View style={H.privacyCard}>
              <Image source={{ uri: BIRD_48 }} style={{ width: 36, height: 18, alignSelf: 'center', marginBottom: 6 }} resizeMode="contain" />
              <Text style={H.privacyText}>All data stays on your phone only.{'\n'}No server. No cloud. No tracking.</Text>
              <Text style={{ fontSize: 9, color: C.t4, textAlign: 'center', marginTop: 6, letterSpacing: 0.5 }}>© Sandeep Hakki · hakki.in · 2026</Text>
            </View>
          </View>
        </Animated.View>
      </ScrollView>
    </View>
  );
};

