  merchant: { fontSize: 15, fontWeight: '700', color: C.t1 },
  meta: { fontSize: 11, color: C.t4, marginTop: 2 },
  amount: { fontSize: 17, fontWeight: '800', color: C.t1 },
  actionRow: { flexDirection: 'row', gap: 8, marginBottom: 10 },
  editBtn: { paddingHorizontal: 12, paddingVertical: 7, borderRadius: 10, backgroundColor: '#eff6ff', borderWidth: 1, borderColor: '#bfdbfe' },
  editBtnText: { fontSize: 12, color: '#2563eb', fontWeight: '700' },
  deleteBtn: { paddingHorizontal: 12, paddingVertical: 7, borderRadius: 10, backgroundColor: '#fff1f2', borderWidth: 1, borderColor: '#fecdd3' },
  deleteBtnText: { fontSize: 12, color: C.lux, fontWeight: '700' },
