// EDUCATION
// ═══════════════════════════════════════════════════════════
const EducationScreen = ({ nav }: any) => {
  const [open, setOpen] = useState<number | null>(0);
  const sections = [
    { title: 'What is Spend-na?', items: [
      { t: 'p', text: 'Spend-na is not a budget app. It is not a tracker. It is a mirror.' },
      { t: 'p', text: 'When you use UPI or a card, money leaves silently. No sound. No weight. Spend-na makes that invisible money visible — not to judge, but to help you see clearly.' },
      { t: 'h', text: 'No guilt. No advice. No lectures. Just awareness.' },
    ]},
    { title: 'How does it work?', items: [
      { t: 's', n: '1', text: 'Your bank sends an SMS every time money leaves. Spend-na reads those messages with your permission.' },
      { t: 's', n: '2', text: 'Each transaction appears as a card. You tap one of four buckets. 2 seconds per transaction.' },
      { t: 's', n: '3', text: 'Your Picture screen shows a colour bar — how your month is split across buckets.' },
      { t: 's', n: '4', text: 'At end of month, tap any slice and answer: Was it a good month? That reflection is the whole point.' },
      { t: 'h', text: 'Nothing leaves your phone. Ever. No account needed.' },
    ]},
    { title: 'The 4 Buckets', items: [
      { t: 'b', key: 'necessary',   body: 'Things you cannot live without. Food, rent, electricity, medicines, school fees. If you skip it, something breaks.' },
      { t: 'b', key: 'committed',   body: 'Money already spoken for. EMI, home loan, SIP, LIC, insurance. You chose these once. Now they are automatic obligations.' },
      { t: 'b', key: 'comfortable', body: 'A good life, not a lavish one. Eating out occasionally, Uber, weekend outing. You could reduce this if needed.' },
      { t: 'b', key: 'luxury',      body: 'Pure want. High-end restaurants, premium gadgets, impulse buys. Knowing it is luxury is the point.' },
    ]},
    { title: 'What goes where?', items: [
      { t: 'e', bucket: 'necessary',   items: 'Vegetables, dal, rice, milk, eggs, gas, rent, electricity, water, medicines, doctor, bus fare, school fees, petrol for commute' },
      { t: 'e', bucket: 'committed',   items: 'Home loan EMI, car loan, personal loan, SIP, RD, PPF, LIC premium, health insurance, term insurance, Netflix, Prime' },
      { t: 'e', bucket: 'comfortable', items: 'Swiggy weekly, Ola when needed, decent restaurant, new shoes, weekend movie, grocery splurge, gym, mobile recharge' },
      { t: 'e', bucket: 'luxury',      items: 'Five-star dinner, premium phone when current works, business class, designer bag, gaming console, spa' },
      { t: 'h', text: 'When in doubt — if money was tight this month, would I still spend this? Yes = Necessary or Committed. Maybe = Comfortable. No = Luxury.' },
    ]},
    { title: 'Tips for beginners', items: [
      { t: 'tip', n: '01', text: 'Do not overthink. Your first instinct is usually right. Tap and move on.' },
      { t: 'tip', n: '02', text: 'Sort every 2-3 days. 5 minutes is enough. Leaving it for a month feels overwhelming.' },
      { t: 'tip', n: '03', text: 'Same item, different bucket for different people. Uber is Necessary if you have no car. Comfortable if you do.' },
      { t: 'tip', n: '04', text: 'Do not set limits too tight in month 1. Watch your natural pattern first.' },
      { t: 'tip', n: '05', text: 'The Yes/No question is the most important feature. Sit with it honestly.' },
      { t: 'h',   text: 'Give it 3 months. After that you will know your money like never before.' },
    ]},
  ];

  const renderItem = (item: any, i: number) => {
    if (item.t === 'p') return <Text key={i} style={{ fontSize: 14, color: C.t2, lineHeight: 23, marginTop: 12 }}>{item.text}</Text>;
    if (item.t === 'h') return <View key={i} style={{ backgroundColor: C.brandL, borderRadius: 10, padding: 12, marginTop: 12, borderLeftWidth: 3, borderLeftColor: C.brand }}><Text style={{ fontSize: 13, color: C.brandD, fontWeight: '700', lineHeight: 21 }}>{item.text}</Text></View>;
    if (item.t === 's') return (
      <View key={i} style={{ flexDirection: 'row', gap: 10, marginTop: 12, alignItems: 'flex-start' }}>
        <View style={{ width: 26, height: 26, borderRadius: 13, backgroundColor: C.brand, alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>
          <Text style={{ fontSize: 12, fontWeight: '900', color: C.dark }}>{item.n}</Text>
        </View>
        <Text style={{ fontSize: 14, color: C.t2, lineHeight: 22, flex: 1, paddingTop: 2 }}>{item.text}</Text>
      </View>
    );
    if (item.t === 'tip') return (
      <View key={i} style={{ flexDirection: 'row', gap: 10, marginTop: 10 }}>
        <Text style={{ fontSize: 11, fontWeight: '900', color: C.brand, width: 22, paddingTop: 3 }}>{item.n}</Text>
        <Text style={{ fontSize: 14, color: C.t2, lineHeight: 22, flex: 1 }}>{item.text}</Text>
      </View>
    );
    if (item.t === 'b') return (
      <View key={i} style={{ borderLeftWidth: 3, borderLeftColor: B[item.key].color, borderRadius: 10, backgroundColor: C.bg, padding: 12, marginTop: 10 }}>
        <View style={{ flexDirection: 'row', alignItems: 'center', gap: 10, marginBottom: 6 }}>
          <BucketIcon bucket={item.key} size={32} />
          <Text style={{ fontSize: 15, fontWeight: '800', color: B[item.key].color }}>{B[item.key].label}</Text>
        </View>
        <Text style={{ fontSize: 13, color: C.t2, lineHeight: 21 }}>{item.body}</Text>
      </View>
    );
    if (item.t === 'e') return (
      <View key={i} style={{ borderLeftWidth: 3, borderLeftColor: B[item.bucket].color, borderRadius: 10, backgroundColor: C.bg, padding: 12, marginTop: 10 }}>
        <View style={{ flexDirection: 'row', alignItems: 'center', gap: 8, marginBottom: 4 }}>
          <BucketIcon bucket={item.bucket} size={26} />
          <Text style={{ fontSize: 12, fontWeight: '800', color: B[item.bucket].color }}>{B[item.bucket].label}</Text>
        </View>
        <Text style={{ fontSize: 12, color: C.t3, lineHeight: 19 }}>{item.items}</Text>
      </View>
    );
    return null;
  };

  return (
    <View style={{ flex: 1, backgroundColor: C.bg }}>
      <ScreenHeader title="How it works" onBack={() => nav('Home')} />
      <ScrollView style={{ flex: 1 }} contentContainerStyle={{ padding: 18, paddingBottom: 40 }} showsVerticalScrollIndicator={false} bounces>
        <View style={{ backgroundColor: C.dark, borderRadius: 20, padding: 22, marginBottom: 18, alignItems: 'center' }}>
          <Text style={{ fontSize: 32, fontWeight: '900', color: C.brand, letterSpacing: -1, marginBottom: 4 }}>Spend-na</Text>
          <Text style={{ fontSize: 13, color: C.t4, marginBottom: 14 }}>Making digital money visible</Text>
          <View style={{ width: 36, height: 2, backgroundColor: C.brand, borderRadius: 1, marginBottom: 14 }} />
          <Text style={{ fontSize: 14, color: '#e2e8f0', textAlign: 'center', fontStyle: 'italic', lineHeight: 22 }}>Not a budget app. Not a tracker.{'\n'}A mirror for your money.</Text>
        </View>
        {sections.map((sec, idx) => (
          <View key={idx} style={{ backgroundColor: C.card, borderRadius: 16, marginBottom: 8, borderWidth: 1, borderColor: C.cardB, overflow: 'hidden' }}>
            <TouchableOpacity style={{ padding: 16, flexDirection: 'row', justifyContent: 'space-between', alignItems: 'center' }} onPress={() => setOpen(open === idx ? null : idx)}>
              <Text style={{ fontSize: 15, fontWeight: '700', color: C.t1, flex: 1 }}>{sec.title}</Text>
              <Text style={{ fontSize: 18, color: C.brand, fontWeight: '700' }}>{open === idx ? '−' : '+'}</Text>
            </TouchableOpacity>
            {open === idx && (
              <View style={{ paddingHorizontal: 16, paddingBottom: 16, borderTopWidth: 1, borderTopColor: C.cardB }}>
                {sec.items.map((item: any, i: number) => renderItem(item, i))}
              </View>
            )}
          </View>
        ))}
        <View style={{ backgroundColor: C.dark, borderRadius: 18, padding: 20, marginTop: 8, alignItems: 'center' }}>
          <Text style={{ fontSize: 13, color: '#94a3b8', textAlign: 'center', lineHeight: 22, fontStyle: 'italic' }}>
            Spend-na was built on one belief:{'\n'}Awareness, not guilt, changes behaviour.
          </Text>
        </View>

        {/* Hakki Branding */}
        <View style={{ backgroundColor: C.dark2, borderRadius: 18, padding: 20, marginTop: 8, alignItems: 'center', borderWidth: 1, borderColor: C.darkB }}>
          <Image source={{ uri: BIRD_96 }} style={{ width: 80, height: 40 }} resizeMode="contain" />
          <Text style={{ fontSize: 13, fontWeight: '800', color: C.brand, letterSpacing: 1, marginTop: 8 }}>HAKKI CONSULTING</Text>
          <Text style={{ fontSize: 11, color: C.t4, marginTop: 4 }}>Built with ♥ by Sandeep Hakki</Text>
          <TouchableOpacity onPress={() => Linking.openURL('http://www.hakki.in')} style={{ marginTop: 6 }}>
            <Text style={{ fontSize: 11, color: C.brand, textDecorationLine: 'underline' }}>www.hakki.in</Text>
          </TouchableOpacity>
          <Text style={{ fontSize: 10, color: C.t4, marginTop: 10, textAlign: 'center', lineHeight: 16 }}>
            © 2026 Sandeep Hakki · All rights reserved{'\n'}Spend-na is a product of Hakki Consulting
          </Text>
        </View>
      </ScrollView>
    </View>
  );
};

// ═══════════════════════════════════════════════════════════
// LIMITS
// ═══════════════════════════════════════════════════════════
const LimitsScreen = ({ nav, limits, onSaveLimits, summary }: any) => {
  const [editing, setEditing] = useState<any>({ ...limits });
  const [activeKey, setActiveKey] = useState<string | null>(null);

  const handleSave = () => {
    const parsed: any = {};
    let valid = true;
    Object.keys(editing).forEach(key => { const val = parseFloat(editing[key]); if (isNaN(val) || val < 0) { valid = false; } else { parsed[key] = val; } });
    if (!valid) { Alert.alert('Invalid', 'Please enter valid amounts.'); return; }
    onSaveLimits(parsed);
    Alert.alert('Saved', 'Budget limits updated.', [{ text: 'Done', onPress: () => nav('Home') }]);
  };

  return (
    <View style={{ flex: 1, backgroundColor: C.bg }}>
      <ScreenHeader title="Budget Limits" onBack={() => nav('Home')}
        right={<TouchableOpacity style={{ backgroundColor: C.brand, paddingHorizontal: 14, paddingVertical: 7, borderRadius: 14 }} onPress={handleSave}><Text style={{ fontWeight: '700', color: C.dark, fontSize: 13 }}>Save all</Text></TouchableOpacity>}
      />
      <ScrollView style={{ flex: 1 }} contentContainerStyle={{ padding: 16, paddingBottom: 40 }} showsVerticalScrollIndicator={false} bounces keyboardShouldPersistTaps="handled">
        <View style={{ backgroundColor: C.dark, borderRadius: 18, padding: 18, marginBottom: 16 }}>
          <Text style={{ fontSize: 16, fontWeight: '800', color: C.white, marginBottom: 6 }}>Your monthly limits</Text>
          <Text style={{ fontSize: 13, color: '#94a3b8', lineHeight: 21 }}>Set your own ceiling for each bucket. You are in control — change these any time.</Text>
        </View>
        {Object.entries(B).map(([key, cfg]: any) => {
          const spent = summary[key] || 0;
          const limit = parseFloat(editing[key]) || 0;
          const pct = limit > 0 ? Math.min((spent / limit) * 100, 100) : 0;
          const isOver = limit > 0 && spent > limit;
          const isNear = limit > 0 && pct >= 80 && !isOver;
          return (
            <View key={key} style={{ backgroundColor: C.card, borderRadius: 18, padding: 14, marginBottom: 12, borderWidth: 1, borderColor: isOver ? C.danger : C.cardB }}>
              <View style={{ flexDirection: 'row', alignItems: 'center', gap: 10, marginBottom: 12 }}>
                <BucketIcon bucket={key} size={42} />
                <View style={{ flex: 1 }}>
                  <Text style={{ fontSize: 15, fontWeight: '800', color: C.t1 }}>{cfg.label}</Text>
                  <Text style={{ fontSize: 11, color: C.t4 }}>{cfg.tag}</Text>
                </View>
                {isOver && <View style={{ backgroundColor: '#fff1f2', paddingHorizontal: 8, paddingVertical: 3, borderRadius: 8 }}><Text style={{ fontSize: 10, fontWeight: '800', color: C.danger }}>OVER</Text></View>}
                {isNear && !isOver && <View style={{ backgroundColor: '#fef3c7', paddingHorizontal: 8, paddingVertical: 3, borderRadius: 8 }}><Text style={{ fontSize: 10, fontWeight: '800', color: C.warning }}>NEAR</Text></View>}
              </View>
              <View style={{ flexDirection: 'row', justifyContent: 'space-between', marginBottom: 10 }}>
                <View><Text style={{ fontSize: 10, color: C.t4, marginBottom: 2 }}>Spent this month</Text><Text style={{ fontSize: 17, fontWeight: '800', color: isOver ? C.danger : cfg.color }}>Rs. {spent.toLocaleString('en-IN')}</Text></View>
                {limit > 0 && <View style={{ alignItems: 'flex-end' }}><Text style={{ fontSize: 10, color: C.t4, marginBottom: 2 }}>{isOver ? 'Exceeded by' : 'Remaining'}</Text><Text style={{ fontSize: 17, fontWeight: '800', color: isOver ? C.danger : C.nec }}>Rs. {Math.abs(limit - spent).toLocaleString('en-IN')}</Text></View>}
              </View>
              {limit > 0 && (
                <View style={{ marginBottom: 12 }}>
                  <View style={{ height: 7, backgroundColor: cfg.light, borderRadius: 4, overflow: 'hidden' }}>
                    <View style={{ height: 7, width: `${pct}%`, backgroundColor: isOver ? C.danger : isNear ? C.warning : cfg.color, borderRadius: 4 }} />
                  </View>
                  <Text style={{ fontSize: 10, color: isOver ? C.danger : C.t4, fontWeight: '600', marginTop: 3 }}>{Math.round(pct)}% of Rs.{limit.toLocaleString('en-IN')} limit</Text>
                </View>
              )}
              <Text style={{ fontSize: 10, color: C.t4, letterSpacing: 1, fontWeight: '700', marginBottom: 8 }}>MONTHLY LIMIT</Text>
              <View style={{ flexDirection: 'row', alignItems: 'center', backgroundColor: C.bg, borderRadius: 12, paddingHorizontal: 12, paddingVertical: 10, borderWidth: 1.5, borderColor: activeKey === key ? cfg.color : C.cardB }}>
                <Text style={{ fontSize: 15, color: C.t3, fontWeight: '600', marginRight: 4 }}>Rs.</Text>
                <TextInput style={{ flex: 1, fontSize: 19, fontWeight: '700', color: C.t1, padding: 0 }} value={editing[key]?.toString() || ''} onChangeText={val => setEditing((p: any) => ({ ...p, [key]: val }))} keyboardType="numeric" placeholder="0 = no limit" placeholderTextColor={C.t4} onFocus={() => setActiveKey(key)} onBlur={() => setActiveKey(null)} />
                {editing[key] > 0 && <TouchableOpacity onPress={() => setEditing((p: any) => ({ ...p, [key]: '0' }))}><Text style={{ color: C.t4, fontSize: 12, paddingLeft: 8 }}>Clear</Text></TouchableOpacity>}
              </View>
              <View style={{ flexDirection: 'row', alignItems: 'center', gap: 8, marginTop: 10 }}>
                <Text style={{ fontSize: 11, color: C.t4 }}>Quick:</Text>
                {[cfg.defaultLimit * 0.5, cfg.defaultLimit, cfg.defaultLimit * 1.5].map((val: number) => (
                  <TouchableOpacity key={val}
                    style={{ paddingHorizontal: 10, paddingVertical: 5, borderRadius: 8, borderWidth: 1.5, borderColor: Number(editing[key]) === val ? cfg.color : C.cardB, backgroundColor: Number(editing[key]) === val ? cfg.light : C.bg }}
                    onPress={() => setEditing((p: any) => ({ ...p, [key]: val.toString() }))}>
                    <Text style={{ fontSize: 11, color: Number(editing[key]) === val ? cfg.color : C.t3, fontWeight: Number(editing[key]) === val ? '800' : '600' }}>
                      {val >= 1000 ? `${(val / 1000).toFixed(0)}k` : val}
                    </Text>
                  </TouchableOpacity>
                ))}
              </View>
            </View>
          );
        })}
        <TouchableOpacity style={{ alignItems: 'center', padding: 14 }} onPress={() => Alert.alert('Reset?', 'Reset all to defaults?', [{ text: 'Cancel', style: 'cancel' }, { text: 'Reset', onPress: () => setEditing({ ...DEFAULT_LIMITS }) }])}>
          <Text style={{ fontSize: 13, color: C.t4, textDecorationLine: 'underline' }}>Reset to defaults</Text>
        </TouchableOpacity>
      </ScrollView>
    </View>
  );
};

// ═══════════════════════════════════════════════════════════
// TAB BAR — uses bottom inset for home indicator
// ═══════════════════════════════════════════════════════════
const TABS = [
  { key: 'Home',      label: 'Wallet',  symbol: 'W' },
  { key: 'Sort',      label: 'Sort',    symbol: 'S' },
  { key: 'Pie',       label: 'Picture', symbol: 'P' },
  { key: 'History',   label: 'History', symbol: 'H' },
  { key: 'ManualAdd', label: 'Add',     symbol: '+' },
];

const TabBar = ({ current, nav }: any) => {
  const insets = useSafeAreaInsets();
  return (
    <View style={{ flexDirection: 'row', backgroundColor: C.card, borderTopWidth: 1, borderTopColor: C.cardB, paddingBottom: insets.bottom || 8, paddingTop: 8 }}>
      {TABS.map(tab => {
        const active = current === tab.key;
        return (
          <TouchableOpacity key={tab.key} style={{ flex: 1, alignItems: 'center', gap: 3 }} onPress={() => nav(tab.key)}>
            <View style={{ width: 38, height: 28, borderRadius: 9, alignItems: 'center', justifyContent: 'center', backgroundColor: active ? C.brandL : 'transparent' }}>
              <Text style={{ fontSize: 13, fontWeight: '800', color: active ? C.brand : C.t4 }}>{tab.symbol}</Text>
            </View>
            <Text style={{ fontSize: 9, fontWeight: '600', color: active ? C.brand : C.t4 }}>{tab.label}</Text>
          </TouchableOpacity>
        );
      })}
    </View>
  );
};

// ═══════════════════════════════════════════════════════════
// ROOT — wrapped in SafeAreaProvider (THE scroll fix)
// ═══════════════════════════════════════════════════════════
const Main = () => {
  const [screen, setScreen] = useState('Home');
  const [params, setParams] = useState<any>(null);
  const [transactions, setTransactions] = useState(MOCK);
  const [limits, setLimits] = useState({ ...DEFAULT_LIMITS });
  const [notifiedBuckets, setNotifiedBuckets] = useState<string[]>([]);

  const nav = (s: string, p?: any) => { setScreen(s); setParams(p || null); };

  const summary = transactions.reduce((acc: any, t: any) => {
    if (t.bucket) acc[t.bucket] = (acc[t.bucket] || 0) + t.amount;
    acc.total = (acc.necessary || 0) + (acc.committed || 0) + (acc.comfortable || 0) + (acc.luxury || 0);
    return acc;
  }, { necessary: 0, committed: 0, comfortable: 0, luxury: 0, total: 0 });

  useEffect(() => {
    Object.entries(limits).forEach(([key, limit]: any) => {
      if (!limit) return;
      const spent = summary[key] || 0;
      const pct = (spent / limit) * 100;
      if (pct >= 80 && !notifiedBuckets.includes(key)) {
        const isOver = spent > limit;
        setTimeout(() => {
          Alert.alert(
            isOver ? `${B[key].label} limit crossed` : `${B[key].label} nearing limit`,
            isOver
              ? `You spent Rs.${spent.toLocaleString('en-IN')} against your Rs.${limit.toLocaleString('en-IN')} limit.`
              : `You have used ${Math.round(pct)}% of your Rs.${limit.toLocaleString('en-IN')} ${B[key].label} limit.`,
            [{ text: 'Got it', onPress: () => setNotifiedBuckets(p => [...p, key]) }]
          );
        }, 600);
      }
    });
  }, [summary]);

  const onClassify = (id: string, bucket: string) => setTransactions(prev => prev.map(t => t.id === id ? { ...t, bucket } : t));
  const onDelete = (id: string) => setTransactions(prev => prev.filter(t => t.id !== id));
  const onAdd = (item: any) => {
    idCounter++;
    setTransactions(prev => [{
      id: `${idCounter}`, merchant: item.description || 'Manual Entry',
      amount: item.amount, time: new Date().toTimeString().slice(0, 5),
      date: new Date().toLocaleDateString('en-IN', { day: 'numeric', month: 'short' }),
      month: new Date().toLocaleDateString('en-IN', { month: 'short', year: 'numeric' }),
      sms: '', bucket: item.bucket, source: item.source,
    }, ...prev]);
  };
  const exportCSV = (month: string | null) => {
    const data = month ? transactions.filter(t => t.month === month) : transactions;
    if (!data.length) { Alert.alert('No data', 'No transactions to export.'); return; }
    const rows = ['Date,Time,Merchant,Amount,Bucket,Source', ...data.map((t: any) => `"${t.date}","${t.time}","${t.merchant}",${t.amount},"${t.bucket || 'Unsorted'}","${t.source}"`)].join('\n');
    Alert.alert(`CSV — ${month || 'All time'}`, `${data.length} transactions\n\n${rows.slice(0, 500)}`, [{ text: 'Close' }]);
  };

  const hideTab = ['SliceDetail', 'Education', 'Limits'].includes(screen);

  return (
    <View style={{ flex: 1, backgroundColor: C.bg }}>
      <StatusBar barStyle="dark-content" />
      <View style={{ flex: 1 }}>
        {screen === 'Home'        && <HomeScreen nav={nav} summary={summary} transactions={transactions} limits={limits} />}
        {screen === 'Sort'        && <SortScreen nav={nav} transactions={transactions} onClassify={onClassify} onDelete={onDelete} />}
        {screen === 'Pie'         && <PieScreen nav={nav} summary={summary} />}
        {screen === 'SliceDetail' && <SliceDetailScreen nav={nav} bucket={params?.bucket} />}
        {screen === 'History'     && <HistoryScreen nav={nav} transactions={transactions} onClassify={onClassify} onDelete={onDelete} exportCSV={exportCSV} />}
        {screen === 'ManualAdd'   && <ManualAddScreen nav={nav} onAdd={onAdd} />}
        {screen === 'Education'   && <EducationScreen nav={nav} />}
        {screen === 'Limits'      && <LimitsScreen nav={nav} limits={limits} onSaveLimits={setLimits} summary={summary} />}
      </View>
      {!hideTab && <TabBar current={screen} nav={nav} />}
    </View>
  );
};

// SafeAreaProvider wraps everything — this is what fixes scroll on iOS 26
const App = () => (
  <SafeAreaProvider>
    <Main />
  </SafeAreaProvider>
);

export default App;
